prompt --application/shared_components/security/authorizations/user_only
begin
wwv_flow_imp_shared.create_security_scheme(
 p_id=>wwv_flow_imp.id(163672843117508713907)
,p_name=>'User_only'
,p_scheme_type=>'NATIVE_FUNCTION_BODY'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_role USERS.ROLE%TYPE;',
'BEGIN',
'  SELECT ROLE',
'    INTO l_role',
'    FROM USERS',
'   WHERE username = :APP_USER;',
'',
'  ',
'  IF UPPER(l_role) = ''ADMIN'' THEN',
'    RETURN TRUE;',
'  ELSE',
'    RETURN FALSE;',
'  END IF;',
'',
'EXCEPTION',
'  WHEN NO_DATA_FOUND THEN',
'    RETURN FALSE;',
'  WHEN OTHERS THEN',
'    ',
'    RETURN FALSE;',
'END;',
'',
''))
,p_error_message=>'you are not user'
,p_version_scn=>15656059207490
,p_caching=>'BY_USER_BY_SESSION'
);
end;
