'    SELECT USER_ID, ROLE',
'    INTO v_user_id, v_role',
'    FROM USERS',
'    WHERE UPPER(TRIM(USERNAME)) = UPPER(TRIM(:P9999_USERNAME));  -- replace with your login username item',
