'    APEX_UTIL.SET_SESSION_STATE(''APP_USER_ROLE'', v_role);',
'    APEX_UTIL.SET_SESSION_STATE(''APP_USERNAME'', :P9999_USERNAME);',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        raise_application_error(-20001, ''User not found in USERS table'');',
